INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23212','Туман яром','Українська народна пісня. Виконує: Піккардійська Терція, Олександр Надточій','uk','ukraine_before_1917',NULL,NULL,'Збірник пісень Студентського Братства Львівської політехніки. Львів, 2000.',NULL,'Туман яром, туман долиною,
Туман яром, туман долиною.
За туманом нічого не видно.     | (2)
Тільки видно дуба зеленого.     | (2)
Під тим дубом криниця стояла.   | (2)
В тій криниці дівча воду брало. | (2)
Та й втопило золоте відерце.    | (2)
Засмутило козакові серце.       | (2)
А хто ж теє відерце дістане,    | (2)
Той зі мною на рушничок стане.  | (2)
Обізвався козак молоденький.    | (2)
А я теє відерце дістану,        | (2)
Та й з тобою на рушничок стану. | (2)
Туман яром, туман долиною.      | (2)','[''pisni.org.ua'', ''cat:lirychni'', ''cat:narodni'', ''Пісні про кохання, ліричні'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23212','Туман яром','Туман яром, туман долиною,
Туман яром, туман долиною.
За туманом нічого не видно.     | (2)
Тільки видно дуба зеленого.     | (2)
Під тим дубом криниця стояла.   | (2)
В тій криниці дівча воду брало. | (2)
Та й втопило золоте відерце.    | (2)
Засмутило козакові серце.       | (2)
А хто ж теє відерце дістане,    | (2)
Той зі мною на рушничок стане.  | (2)
Обізвався козак молоденький.    | (2)
А я теє відерце дістану,        | (2)
Та й з тобою на рушничок стану. | (2)
Туман яром, туман долиною.      | (2)');
