INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2321292','Останній дзвоник','Музика: Ігор Римденок Слова: Ольга Безіменна','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дзвенить дзвінок в останній раз,
І трохи сумні його звуки;
Не покличе він більше в клас,
Не покличе він більше в клас -
Він говорить нам про розлуку.
І першокласник пустотливий
Дзвонить в дзвоник, намагаючись,
І наш учитель дорогий,
І наш учитель дорогий
Нам махає, сумно посміхаючись...

Приспів:
Дзвінок останній, як останній вальс,
Випускників по площі закрутить.
Дзвінок останній проводжає нас
І однокласників навік він здружить!..

Зараз нам скажуть: "У добру путь!
Нехай буде світлою дорога!"
І буде сумно нам трохи,
І буде сумно нам трохи
Піти із шкільного порога.
Дзвенить дзвінок в останній раз,
І трохи сумні його звуки;
Не покличе він більше в клас,
Не покличе він більше в клас -
Він говорить нам про розлуку...

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2321292'), datetime('now')),datetime('now'));
