INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2321318','Літо золоте','Музика: Ольга Янушкевич Слова: Марія Ясакова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Прилетіло літо, як на крилах,
Принесло нам літо дні щасливі.
Літо кучеряве, лагідне, як мама,
Ось воно яке - літо золоте...

Приспів:
Я з тобою, літо, пожартую!
Я з тобою, літо, потанцюю!
Я з тобою, літо, поспіваю!
Я тебе ще з осені чекаю!

Розсипає літо срібні роси,
Заплітає літо квіти в коси.
Пахощі суниці, грози і зірниці,
Ось воно яке - літо золоте...

Приспів.

Задрімало літо на покосах,
Засмалило сонцем ноги босі.
Скупане в любистку росяне намисто.
Ось воно яке - літо золоте...

Приспів.    Фонограма-мінус (mp3, 320kbps)','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2321318'), datetime('now')),datetime('now'));
