INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232158','А хто видав а хто слихав Мою Жінку на Торгу','Українська народна пісня. Виконує: Веснівка','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївка: Українське Відродження Світа. Пісня-Гра. Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Вибирай си кого любиш. Правой ручкою обняла ще й поцілувала. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','А хто видав а хто слихав
