INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232175','Де Ти ходив Наш Чорний Баране','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївка: Українське Відродження Світа. Пісня-Гра. Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Вибирай си кого любиш. Правой ручкою обняла ще й поцілувала. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні. Весняне Свято було також важним для молодих, головно із-за вільного запізнавання. Було воно в дохристиянських часах рівнож Святом загальних заручин. А вже Весільні обряди відбувалися внедовзі по Святах. Простолюдин і тепер Весільні обряди більше вважає потрібними для важности шлюбу, як церковні церемонії. Обов''язком свідомих Українців повинно бути не дати ніяк загинути цьому гарному звичаєві, тому нашому заборолові, яке держить народ кріпко при своїм ріднім. Де нема Веснянок, треба покласти собі за ціль вивчити молодіж Ягілок, а коли вони раз приймуться, то вже їх ніхто не викорінить. Богато зібраних мною пісень та етноґрафічних записок забрала мені польська дефензива при богатьох ревізіях і відібрати їх ніяк не можна. Жаден уряд в Польщі не знає, де поділися річи забрані при ревізіях. – М. Миханько','Всі беруться за руки, йдуть Колом співаючи.
Всередині Кола — Чорний Баран у кожусі вовною навиворіт.
Він показує смішними рухами й голосом слова Пісні.
Після останньої в''язки Чорний Баран біжить до Кола і вибирає собі Дівчину, цілує її.
Після цього гра відновлюється з іншим Чорним Бараном.

