INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2325277','Бросай, Петре, жінку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Старовинна пісня (сімейна драма минулих часів) з Півдня України (Таврія).','Бросай, Петре, жінку,
А я - чоловіка,
Та й поїдем на Вкраїну |
Де весело жити!..      | (2)

Ой, боюсь я, Насте,
Щоб нас не впіймали,
Щоби наші білі ручки   |
Назад не зв''язали...   | (2)

Ой, не бійся, Петре,
Не бійся нікого.
А я свого чоловіка     |
Пошлю в яр косити...   | (2)

А він косить, косить,
На дім поглядає -
Усі жінки обід несуть, |
Моєї немає...          | (2)','[''pisni.org.ua'', ''cat:pivden'', ''Пісні з півдня України'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2325277'), datetime('now')),datetime('now'));
