INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232395','Там за Горею за Високею','Українська народна пісня. Виконує: Гуртоправці, — гурт „Володар“, Володар','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Світотворчі містерії. Святе Шиття-Вишивання: Шиє-малює Злотом гаптує. Помічення Пари: По чім Його ви так упізнали. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаївки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Були Світилки Яснії Зірки. Шиє-малює Злотом гаптує. Буде Тобі Три Дорозі. Спутай Коня на Отаву в залізнії пути. Листки з приводу цієї Пісні: День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Стежки до листків про Українські традиції.','Там за Горею за Високею

Приспів:
Грай Коню
Грай Кониченьку Сивий Маленький зо мною зо мною!

А на тім Конику Красний Кавалір Молодий Романко
А на ньому боти Київськой роботи!
При йому Хустечка Шовком вишивана Подарком давана
При боку Шабелька то Його Панєнка Молода Мар''янка','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_232395'), datetime('now')),datetime('now'));
