INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23226','Рушничок','Музика: Ігор Особік Слова: Ігор Особік. Виконує: Андрій Хавунка','uk','ukraine_1991',NULL,NULL,'Збірник пісень Студентського Братства Львівської політехніки.- Львів, 2000.',NULL,'Вишийте мені, мамо,
Рушничок в дорогу.
В бій як піду з більшовиками,  |
Чи верну додому?               |

Вигаптуйте мені, ненько,
Та вмийте сльозами,
Я його прикладу                |
до свого серденька -    |
Легше буде воювати.            | (2)

Відріжте мені, мамо,
Від нього половину,
Я подарую на добру згадку      |
Коханій дівчині                | (2)

Поцілую й подарую
Весільного рушничка я,
Най би дуже не плакала,        |
Свого Степана чекала.          | (2)

Не журіться ви, мій тату,
Не плачте, моя нене,
Переможемо московита,          |
Я ще мо'' ся поверну.           | (2)','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23226'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23226','Рушничок','Вишийте мені, мамо,
Рушничок в дорогу.
В бій як піду з більшовиками,  |
Чи верну додому?               |

Вигаптуйте мені, ненько,
Та вмийте сльозами,
Я його прикладу                |
до свого серденька -    |
Легше буде воювати.            | (2)

Відріжте мені, мамо,
Від нього половину,
Я подарую на добру згадку      |
Коханій дівчині                | (2)

Поцілую й подарую
Весільного рушничка я,
Най би дуже не плакала,        |
Свого Степана чекала.          | (2)

Не журіться ви, мій тату,
Не плачте, моя нене,
Переможемо московита,          |
Я ще мо'' ся поверну.           | (2)');
