INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2326395','Синє небо - жовте поле','Музика: А. Фурдичко Слова: А. Фурдичко. Виконує: Андрій Князь','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Україна моя рідна - це моя земля!
Тут родилися на світ батько, мати, я!
А Карпати - рідна хата, смерековий край,
Українську нашу пісню, грай, музико, грай!

Приспів:
А у нас небо - синє небо!
А у нас поле - жовте поле!
А у нас люди - щирі люди!
Ми - одна сім''я!
А у нас вітер - вільний вітер!
А у нас море - Чорне море!
А у нас квіти - сонця квіти!
Вічна ця земля!

Ми усі - одна родина, доля з джерела,
І від батька, і до сина силу козака,
І від матері, і доні вірність і красу
Дітям нашим поколінням гордо донесу!

Приспів.','[''pisni.org.ua'', ''cat:patriotic'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2326395'), datetime('now')),datetime('now'));
