INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232471','Ой сяду я Край Віконця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пара - любощі: Човник-Весельце. Кінь-Вода. Мати. Стародавні Колядки-Щедрівки - Купальські: Українське Різдво / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Були Світилки Яснії Зірки. На Святе Різдво тай на Рождество Ой в Бару Бару Валохи гудуть Ой на Річці на Ордані (2) На Городі Корито Корито Якби Човен та Весельце рятувала б моє Серце. Стала Вода прибувати Чорноморець потопати. А нас Мати рано побудила Взяло Дівча Ведро тай пішло по Воду Візьму я Коновку тай піду по Воду Зеленая Ліщинонько чом не гориш Місяць на Небі Зіроньки сяють Ой пливе Човен по Росі Ой сяду я Край Віконця Ой ти Коте Рябку Пливе Човен Води повен Реве та стогне Дніпр широкий Човен хитається серед Води Чув я чи то снилось мені (Країна Мрій) Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції.','Ой сяду я Край Віконця
Проти Ясного Сонця,
Проти Ясного Сонця
Виглядати Чорноморця.

Чорноморець, Мати, їде
Ще й Семеро Коней веде,
На Восьмому Вороному
У Жупані Голубому.

У Жупані Голубому,
Я ж думала, що додому,
А він їде аж до Гаю,
Аж до Тихого Дунаю.

Ой став Коня напувати,
Стала Вода прибувати.
Стала Вода прибувати,
Чорноморець потопати.

Чорноморець потопає
Та на Милую гукає:
Рятуй-рятуй, Моя Мила,
Коли вірно любила!

Ой, рада б я рятувати -
Так не вмію я плавати,
Якби Човен та Весельце
Рятувала б моє Серце!

Ой, піду я поміж люди,
Чи не жаль кому буде!
Заким люди зібралися,
Чорноморець утопився.

Пливи, пливи за водою,
Зосталася я вдовою!
Пливи, пливи берегами,
Зосталася з ворогами!','[''pisni.org.ua'', ''cat:kupalski'', ''cat:vesnyanky-hayivky'', ''Купальські пісні'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_232471'), datetime('now')),datetime('now'));
