INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2329716','Мантра','Музика: Фагот Слова: Фагот. Виконує: Танок на майдані Конго','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Одягнувшись завісою Христа,
Шкіра моя - панцир залізний,
Кров - руда міцна,
Кість - меч булатний,
Швидше стріли, пильніше сокола.

Приспів:
Броня на мені, Господь в мені!..
Броня на мені, Господь в мені!..
Броня на мені, Господь в мені!..
Амінь...

Розійшлись хмарки, гляне сонечко,
Заб''ється в грудях моє серденько.
Ой, прийшла весна, ой, прийшла красна,
Принесла мені щастя й радощі...

Приспів.','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2329716'), datetime('now')),datetime('now'));
