INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2328550','До милої','Українська народна пісня. Виконує: Rock-H (Рокаш)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Я не буду пиво пити, бо пиво гурькоє,
А лем буду любовати дівча солодкоє.
Та й не буду я ходити горами-долами
За чужима, за чужима жонами, дівками.
А я пуйду до милої...

Приспів:
До милої, до милої,       |
До милої, та й до тої,    |
Што без неї та й умирать, |
Серце моє, серце моє!..   | (2)

Ей-гой моя білявина на горі високуй,
Її личко рум''яноє не дає ми покуй.
А я пуйду до дівини, та й буду казати,
Ци мож з тобов, солоденька, мало фігльовати.
А я пуйду до милої...
А я пуйду до милої...

Приспів.','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2328550'), datetime('now')),datetime('now'));
