INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2331498','Гей, озовись, трембіто!','Музика: Леопольд Ященко Слова: Леопольд Ященко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Гей, озовись, трембіто,
Затрембітай горами!
Знову на долину
Стежечка крута
Стелиться перед нами!

Гей, озовись, трембіто,
Гей, зашуми, смереко!
Через бистру річку,
Через темний гай
Путь нам лежить далека!

Гей, озовіться, гори,
Ви чарівні Карпати!
Гей, як ми поїдем
В дальню сторону,
Хто ж буде вам співати?
(Гей, прощавайте, гори,
Сині мої Карпати!
Гей, як я поїду
В дальню сторону,
Хто ж буде вам співати?)

Гей, прощавайте, гори,
Та й до нового літа!
Буде вам співати
Пташечка в бору
Ще й голосна трембіта!','[''pisni.org.ua'', ''cat:himny-marshi'', ''cat:manrivni'', ''Гимни та марші'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2331498'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2331498','Гей, озовись, трембіто!','Гей, озовись, трембіто,
Затрембітай горами!
Знову на долину
Стежечка крута
Стелиться перед нами!

Гей, озовись, трембіто,
Гей, зашуми, смереко!
Через бистру річку,
Через темний гай
Путь нам лежить далека!

Гей, озовіться, гори,
Ви чарівні Карпати!
Гей, як ми поїдем
В дальню сторону,
Хто ж буде вам співати?
(Гей, прощавайте, гори,
Сині мої Карпати!
Гей, як я поїду
В дальню сторону,
