INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2327461','Забудь мене, моя матусю','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930',NULL,'Уснословесний жанр повстанська пісня Місце побутування смт Запитів, Кам''янка-Бузький район, Львівська область Респондент Максимишин Марія Олексіївна, 1930 р.н. Збирачі Вовчак Андрій, Мартиник Соломія','Забудь мене, моя матусю,
Забудь мене, шо я - твій син -
Як був малий, то ти раділа,
А як підріс, кати взяли...

Не було сили боронити,
Не було сили, бо стара...
Кати злетісь, мов ті круки, -
І закували юнака.

Здригнулось тіло від побоїв,
Стиснули руки кайдани,
І кайданами забряжчав я...
Кати промовили: "Вже йди!"

Відходячи я попрощався:
Прощай, родинонько моя!
Прощай, родино, Україно!
Більш не побачу тебе я...

Більш не побачиш свого сина
Ні у гаях, ні у лісах...
Лише побачиш через сльози,
Закованого в кайданах...

А як привезли мене в темницю,
Як кинули мене туди,
Коли я гляну навкруг себе -
Сидять заковані брати...

Прийшов катюга самий старший:
"Отак вам, вкраїнські сини,
Не схочете більш України,
На вас покопані ями".

Нехай нас б''ють, нехай катують,
Нехай з нас роблять, що хотять,
Нехай нас в тюрми замикають,
На них ще прийде помсти час!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2327461'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2327461','Забудь мене, моя матусю','Забудь мене, моя матусю,
Забудь мене, шо я - твій син -
Як був малий, то ти раділа,
А як підріс, кати взяли...

Не було сили боронити,
Не було сили, бо стара...
Кати злетісь, мов ті круки, -
І закували юнака.

Здригнулось тіло від побоїв,
Стиснули руки кайдани,
І кайданами забряжчав я...
Кати промовили: "Вже йди!"

Відходячи я попрощався:
Прощай, родинонько моя!
Прощай, родино, Україно!
Більш не побачу тебе я...

Більш не побачиш свого сина
Ні у гаях, ні у лісах...
Лише побачиш через сльози,
Закованого в кайданах...

А як привезли мене в темницю,
Як кинули мене туди,
Коли я гляну навкруг себе -
Сидять заковані брати...

Прийшов катюга самий старший:
"Отак вам, вкраїнські сини,
Не схочете більш України,
На вас покопані ями".

Нехай нас б''ють, нехай катують,
Нехай з нас роблять, що хотять,
Нехай нас в тюрми замикають,
На них ще прийде помсти час!');
