INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233091','Нова Радість стала, Світу ся з''явила','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1990','Багатотиражка Дрогобиччини "Галицька зоря" за 5 січня 1991 року.','Записана 1990 року від аматорів хору "Відродження" Дрогобицького Товариства української мови "Просвіта" імені Тараса Шевченка.','Нова Радість стала,
Світу ся з''явила,
Де Пречиста, Чиста Діва Мати
Сина породила.

Як ''Го породила,
В Пелени повила,
Сінцем Красним, Красним, як Лелія,
Його притрусила.

А як ся Жидове
О Тім довідали,
За Марієв, Ісусом Маленьким
Щонайскорше гнали...

А Марія Мати
В Лісі ночувала,
В Лісі, в Лісі, в Лісі при Дорозі
Вогонь розкладала.

Вогонь розложила,
Дала Людям знати,
Щоби Люди, Люди приходили
Дитятко витати.    Мелодія для одного голосу','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:halycki'', ''cat:kolyadky'', ''Церковні пісні'', ''Пісні з Галичини'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233091'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_233091','Нова Радість стала, Світу ся з''явила','Нова Радість стала,
