INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2331550','Відкриваються простори','(Морська похідна)','uk','ukraine_1991',NULL,NULL,'аудіозапис','Мелодія пісні Сергія й Тетяни Нікітіних "На далекой Амазонке".','Відкриваються простори,
Берег тане вдалині.
Попереду тільки море
І мандрівки довгі дні.
Вітер свище, хвиля грає,
Але знаєм я і ти -
Хто нічого не боїться,
Завжди дійде до мети!

Приспів:
Коли ми знов повернемось
До рідних берегів,
То друзів привітаємо,
Забудем ворогів.
Тоді поллються ріками
І пісня, і вино,
А всі незгоди й прикрощі
Нехай ідуть на дно!
Та не забудемо ніколи,
Як бриніли ясні зорі,
Як солоні хвилі моря
Нас носили по світах!
Не забудемо ніколи,
Як бриніли ясні зорі,
Як солоні хвилі моря
Нас носили по світах!

На нашій шхуні все гаразд,
Компас не збреше нам.
На карті світу після нас
Не буде білих плям!
Ми обійдемо цілий світ,
І у чужих краях,
Де ми були, замайорить
Наш синьо-жовтий стяг!

Приспів.

І може, як пройдемо
Крізь бурі і шторми,
То з капітаном Немо
Зустрінемося ми -
На островах незнаних
Десь на краю землі,
Там він для нас із вами
Будує кораблі...

Приспів.','[''pisni.org.ua'', ''cat:manrivni'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2331550'), datetime('now')),datetime('now'));
