INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2331512','Під небом кочовим','Музика: Оксана Рафа Слова: Ліна Костенко, Ростислав Крамар','uk','ukr_ssr_1919_1991',NULL,'1990','аудіозапис','Пісня запозичена у 1990-тих роках від тернопільського Товариства "Вертеп".','Під небом кочовим ребристі халабуди,
Пронизлива печаль - віки, віки, віки...
Поезія-народ - про нас говорять люди,
Поезія-народ... - А ми - кочівники...

Приспів:
Гей, дана-дан,
Гей, дана, дана, дана, дана, дана,
О-о-о-о-о-о-о-о, гей!
Гей, дана-дан,
Гей, дана, дана, дана, дана, дана,
О-о-о-о-о-о-о-о, о!

Загубляться сліди і стихне спів за нами,
Залишаться в степах багаття-вартові,
І котиться життя незнаними стежками
На незборимий клич циганської зорі.

Приспів.

Циганкам ворожить, циганам коні красти,
І повертатись знов під ненадійний дах.
І хоч життя таке ще проклянеш не раз ти,
Та житиме наш дух мандрівний у піснях.

Приспів.

Ковтати пил шляхів і забувати втому,
І знати наперед перебіг всіх доріг...
Переплелись для нас відоме й невідоме,
І праведні слова, і споконвічний гріх.

Приспів.','[''pisni.org.ua'', ''cat:manrivni'', ''Пісні на мандрівну тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2331512'), datetime('now')),datetime('now'));
