INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333591','Молитва на Різдво','Музика: Зиновій Медюх Слова: Зиновій Медюх. Виконує: Зиновій Медюх, Оксана Муха, Піккардійська Терція','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На Різдво, на Святий Вечір
Позбиралася малеча,
Мати кутю вже поставила на стіл...
В хаті в нас когось бракує -
Діти, тато наш воює,
Молимось, щоб повернувся він!..
Молимось, щоб повернувся він!..

Та молитва на Різдво
Збереже в бою його
І Оленка зачекалась
Свого тата:
Миколаї всі святі,
Поверніть його мені,
І не треба більш
Нічого дарувати!
І не треба більш
Нічого дарувати!

Богородице Маріє,
Чорний вітер з Сходу віє,
Хочу я, щоб оминув він
Нашу хату!
Наш Івасик народився,
В нього зубчик лиш пробився,
Він ні разу ще не бачив
Свого тата!
Він ні разу ще не бачив
Свого тата!

Та молитва на Різдво
Збереже його в АТО
І Оленка зачекалась
Свого тата:
Миколаї всі святі,
Поверніть його мені,
І не треба більш
Нічого дарувати!
І не треба більш
Нічого дарувати!

Миколай поправив вуса,
Почесав по бороді,
Запитав у всіх ангелів
Тих, що були на війні:
Чи живий Оленки тато,
Чи поверне до села?
Не беруть його гранати -
Богородиця спасла!
Не беруть його гранати -
Богородиця спасла!

Та молитва на Різдво
Зберегла його в АТО
І Оленка дочекалась
Свого тата!
Миколаї всі святі,
Зберегли його мені,
І не треба більш
Нічого дарувати!
І не треба більш
Нічого дарувати!','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333591'), datetime('now')),datetime('now'));
