INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333910','Новорічна','Музика: DZHERELA Слова: DZHERELA. Виконує: DZHERELA','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Розсипає щедрий вечір добрий сніг,
З неба лине янголиний срібний сміх,
Посміхнуться зорі нам в канун Різдва,
А навколо - сніг, а навколо - сніг
І справжні чудеса! Чудеса!

Приспів:
Кличе Рік Новий в дорогу:
Поспішай! Поспішай!
Казку добру і стару
Ти пригадай!
Відрахує час годинник -
Так і знай!
Кличе Рік Новий в дорогу:
Поспішай! Поспішай!
Казку добру і стару
Ти пригадай!
Відрахує час годинник -
Так і знай!
В новорічну ніч
У казку поспішай!

У серпанку новорічнім сніг кружля,
Карнавал зірок зустрінем ти і я!
Зачаклує щастям нічка чарівна,
Заіскриться ясно, заіскриться ясно
Зірка в небесах! В небесах!

Приспів.

Якщо ти, друже, віриш в чудеса,
Сніжинку у долонях заховай!
І в Рік Новий кохання побажай!
Побажай! О півночі бажання загадай!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333910'), datetime('now')),datetime('now'));
