INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333828','Іде Новий Рік!','Музика: Сергій Родько Слова: Алла Бінцаровська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Іде білий сніг,
Чарує іскринками,
Ми знову милуємось
Диво-сніжинками -
Це зима!
В чарівнім танку
Хурделиця крутиться,
У Році Новому ми вірим:
Все збудеться! -
Це зима!

Іде Новий Рік! -
Він буде кращим, як торік!

Тепленькі шкарпетки,
Рукавиці і муфточки,
А ще добре мати
Пухову курточку! -
Це зима!
Неначе ожив
Сніговик із морквиною
І вже Дід Мороз
Поспішає з торбиною! -
Це зима!

Іде Новий Рік! -
Він буде кращим, як торік!','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333828'), datetime('now')),datetime('now'));
