INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233461','Ой чи є чи нема Пан Господар Дома','Українська народна пісня. Виконує: Тріо Либідь, Олександр Гаркавий','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Радуйся Земле Коляда їде! Читати листки з приводу цієї Пісні: Ідея Бога на Свят-Вечер. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Українські релігійні роздуми про Бога: Яблучко. Стежки до інших листків про Українські традиції.','Ой чи є чи нема Пан Господар Дома

Приспів за зразком: Щедрий Вечір Добрий Вечір
Пан Господар Дома!

