INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2335175','Подарунок','Музика: Анна Олєйнікова Слова: Анна Олєйнікова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У моєї однокласниці
День народження,
Завтра хочу її привітать,
Та біда, що не знаю я,
Що б такого їй подарувать...
Я би міг складну задачу
Замість неї розв''язати,
Тільки, знаю, не захоче
Подарунок, подарунок,
Подарунок цей прийнять.

У моєї однокласниці
День народження,
Завтра будуть всі її вітать,
То, напевне, повинен я
Щось від себе їй подарувать?..
Я б зірвав для неї квітку,
Гарну квітку, краще - три,
Тільки, знаю, нагадає,
Що природу, що природу
Нам потрібно берегти.

У моєї однокласниці
День народження,
Завтра в класі будуть всі вітать.
Зрозуміло, хотів би я
Щось від себе їй подарувать.
Я зловив би їй синицю,
А в придачу журавля,
Подаруй хоч райську птицю -
Знов відпустить її в небо
На свободу знаю я.

Речитатив:
Я б дістав їй з неба зірку,
Здивував би цим усіх,
Вона скаже, я романтик,
А їй зірка ні до чого,
Ні до чого, просто сміх.

У моєї однокласниці
День народження,
Завтра буду я її вітать,
Тільки й досі не знаю я,     |
Що б такого їй подарувать?.. | (2)','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2335175'), datetime('now')),datetime('now'));
