INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2336165','Пісня про Миколая','Музика: Леся Горова Слова: Леся Горова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тиха ніч надворі білим снігом засипана,
Зорі сплять, небо спить,
Гріється в теплому сні,
Але хто, хто це там по дворі ще ходить,
Із мішком у руках хто сміється у вікні?

Приспів:
Це святий Миколай
Всім дарунки розносить,
Хоче за ніч обійти всіх людей,
В кожную хату радість приносить,
Звеселяє наших дітей. | (2)

Крізь вікно загляда він у кожну надію,
У містах і у селах
В найменший провулок зайде.
Хоч малі очки сплять та вирують мрії,
Він за мить їх здійснить,
Під подушку покладе.

Приспів.

Хай в цей день на землі
Оживе добра казка.
Хай щасливим і здоровим
Прокинеться кожне дитя.
І на всі маленькі душі
Зійде Божа ласка,
І в цю мить, і в цей час,
І на все, на все життя.

Приспів.','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2336165'), datetime('now')),datetime('now'));
