INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233675','А в Ліску в Ліску на Жовтім Піску','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Можна співати, як відміну: Росте Деревко Тонке й Високе. В Чистому Полі Сам Плужок ходить. А всі Святії за Погоничів за Посівачів. Пракультурні зразки. Колядка - Гей понад Лужок оре там Плужок - мусить бути дуже старинна, бо хоч у першій частині очевидна вища рільнича культура, але злучено з нею Місячно-мітольоґічну символіку: Воли своїми Рогами (ще й Золотими) є символами Місяця; Чотири Воли є мабуть символами чотирьох Місячних фаз. А конець Колядки дуже близький до пракультури, бо Сокіл є також фіґурою Місячною, але образець про клеєння постріту (цебто усього стрілецького оружжя, лука і стріл) і про попюрування стріл належить хіба до чисто пракультурних. Серед таких обрамовань мусимо і образці Молодецьких і Дівоцьких, окремих, робітничих гуртків вважати за дуже старинні. Прадідна доба. Ідеальні Села. Статеві громади. Анальоґічна наступна Колядка — класична Українською збірною Місячною символікою і характеристикою Прадідної доби: А в Ліску в Ліску на Жовтім Піску. Що в Староукраїнців був фактично поділ дозрілої молоді громадами за статями, свідчать дані про це, що коли в наслідок такого поділу оставалися старші люди і родини з дітворою, та вони творили окреме зборище. Про те співають Колядки і Щедрівки. Такий поділ громадян на три ґрупи був задержуваний постійно і до нього застосовувано громадські і господарські справи. Подаємо понижче Колядки про Жнива, при котрих брано цей поділ під увагу; а дальше Колядкові й Щедрівкові згадки про формальні села, громади — окремо Старих людей, окремо Хлопців, і окремо Дівчат. В цій Колядці (початок без Місячного образця Прадерева, — конець майже тотожний, як під IX) співають: X. Зберемо Женці Ґречні Панянки А Носілочки Молоді Хлопці А Кладільнички Старії Люди.................................... Відміна до цієї Колядки така:................................. Зберемо Женці Дівки Панянки А Носільнички Хлопці Молодці А Вязальники Середні Люди А Пораднички Старії Люди Та хоч тут названо чотири суспільні ґрупи, але очевидна річ, що дві перші — це статеві ґрупи, а дві другі — це розділена громада Старших людей, тільки для того, що Старці не годні працювати; зате вони радять — повчають, що слід робити. Вдаряючий доказ Староукраїнського поділу суспільности на дві статеві громади Молоді і третю Старих людей дають Колядки і Щедрівки, зложені саме на цю тему: Ой Садом Садом тай Виноградом. Щедрівка оця має моральні побудки. Бурлаки-Молодці бачать самі своє змарноване через волокитство життя і просять ідеального Господаря, щоб їм поміг вийти з невідрадного положення. Ідеалом їх є згадані Три Села, до котрих вони могли би пристати, принагідно поженитися, а відтак Господареві відвдячитися. Такі ідеальні Села мусіли бути дуже давно на Україні. Одна Щедрівка ставляє їх у цілком мітичні часи: А в Соколонька я Двір в Острозі. Крім мітольоґійної обстанови (Рай-Дерево; Сокіл з чорними оченьками і бровами — символ Місяця в часі темряви Новю, Молодець-Стрілець, з луком, — як Новий Місяць; женихальна дія в зароді) зарисовуються виразно реальні життєві образці: Перший городок — Господарський, де можна коня дібрати, Другий — Молодецький, де можна Весільних бояр замовити, а Третій городок — Дівоцький, з якого можна Подругу вибрати. Дуже важна характеристика Третього городка: у нім живуть Дівчата не для іграшки мужеської, але з нього беруть Подругу, щоб з нею жити. Читати листки з приводу цієї Пісні: Cвятий Збір, 8 січня: Прадідна доба. Ідеальні Села. Статеві громади. Бог, Різдво Світа, Дідух і Лицарі. Стежки до листків про Українські традиції.','А в Ліску в Ліску на Жовтім Піску
Росте Деревце Тонке Високе
Високе Тонке в Корінь Глубоке
В Корінь Глубоке в Верху Кудряве
На тім Кудрявци Сив Сокіл сидить
Сив Сокіл сидить з Крута ся дивить
Ой видить же він на Чисте Поле

На Чистім Поли сам Плужок оре
Ой за тим Плужком сам Господь ходить
Святий Николай Волики гонить
Свята Пречиста їсточки носить
Ой носить-носить тай Бога просить
Ой оріть Синки та Довгі Нивки
Мемо сіяти Жито-Пшеницю
Жито-Пшеницю всяку пашницю

Скличемо Женців Сімсот Молодців
Да Вязальничок Сімсот Дівочок
Ой звеземо ж ми на Край Дуная
Складемо же ми в Велику Стирту
Тай завершимо Сивим Соколом','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''Колядки'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233675'), datetime('now')),datetime('now'));
