INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2338624','Чекають діти Миколая','Слова: Марія Чайківчанка','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Тихий вечір запалив лампадки святкові,
Сяють-миготять зорі у сяйві золотім,
Падають іскристі сніжинки на долоні
І Миколаю встеляють килим до землі.

У піднебессі в окрасі відзеркалюють перлини,
Видно як вдень засніжені хатки вздовж села,
Блаженний несе подарунки на плечах у торбині
І Місяцем зорить крізь шибку і хукає до вікна.

В цю казкову ніч збуваються усі бажані мрії,
Чекають діти Миколая до сходу першої зорі,
Їм виграють небесні дзвони, ангели пресвятії,
Заколисують, щоб у снах спали діточки малі.

Іде Святий Миколай до нас із  добром і миром,
Із зоряних світів несе жадану надію і любов,
Із Новим роком вітає вкраїнську кожну родину
І залишає частинку свого серця із нових обнов.','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2338624'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2338624','Чекають діти Миколая','Тихий вечір запалив лампадки святкові,
Сяють-миготять зорі у сяйві золотім,
Падають іскристі сніжинки на долоні
І Миколаю встеляють килим до землі.

У піднебессі в окрасі відзеркалюють перлини,
Видно як вдень засніжені хатки вздовж села,
Блаженний несе подарунки на плечах у торбині
І Місяцем зорить крізь шибку і хукає до вікна.

В цю казкову ніч збуваються усі бажані мрії,
Чекають діти Миколая до сходу першої зорі,
Їм виграють небесні дзвони, ангели пресвятії,
Заколисують, щоб у снах спали діточки малі.

Іде Святий Миколай до нас із  добром і миром,
Із зоряних світів несе жадану надію і любов,
Із Новим роком вітає вкраїнську кожну родину
І залишає частинку свого серця із нових обнов.');
