INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2338495','Олекса Довбуш','Слова: Володимир Дашавський','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'авторське подання',NULL,'На Чорногорі ватра палає,
Біля неї Довбуш сидить.
Мольфара Олекса питає:
Скільки на світі мені ще жить?

А мольфар сумно йому каже:
Смерть твоя незабаром прийде,
Бо Дзвінчук - ворог заклятий,
Уже срібну кулю для тебе кує.

Бо Дзвінчук ворог заклятий,
Срібну кулю давно уже має,
Сидить тихенько в своїй хаті,
І й в засідці на тебе чекає.

Та Довбуш наш молоденький
Не повірив в ті пророчі слова,
Та й зійшов він до тої долини,
Де його Дзвінка кохана жила.

Підійшов він до старої хатини,
Плече під двері тисові підклав,
А Дзвінчук, його ворог проклятий,
Срібну кулю йому в груди послав.

Впав Довбуш в груди зранений,
На руки вірних опришків своїх.
Ой, Божечку ж ти наш милий!
Як сильно Олекса наш побілів.

Несіть ви мене, хлопці опришки,
Далеко в рідні Чорногори несіть.
Що я в груди смертельно зранений
Ворогам своїм, того не кажіть.

В Чорногорах я буду спочивати
Та прийде, побратими, той час,
Коли вороги будуть вам докучати,
То дух мій повернеться до вас!

Тоді великою силою повстаньте,
З України ворогів усіх проженіть,
Та й в мирі, злагоді та багатстві
Дружньою громадою, українці, живіть!..','[''pisni.org.ua'', ''cat:boykivski'', ''cat:huculski'', ''cat:strilecki'', ''Пісні з Бойківщини'', ''Гуцульські пісні'', ''Стрілецькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2338495'), datetime('now')),datetime('now'));
