INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233890','Ой Коляда Колядниця дайте Мачку до Кутиці','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські. Радуйся Земле Коляда їде! Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Ой Коляда Колядниця дайте Мачку до Кутиці
Як не дасте одкажіте моїх ніжок не знобіте
Я Дитинка Маленькая в мене ніжка босенькая
Вечір Добрий дайте Пиріг Довгий!
А швидше там виносьте та Людей не морозьте!

Коляд Коляд Колядниця Добра з Маком Паляниця
А без маку не така дай Хазяїн П''ятака
Як не даси п''ятака я Вола за Рога
А Кобилу за Чуприну тай поведу на Тічок
А з Тічка в Кабачок да проп''ю за П''ятачок

Коляда Коляда дайте Дядьку Пирога!
Як не даси Пирога візьму Вола за Рога
Та виведу на Моріг та виломлю Правий Ріг
У Ріг буду трубити Волом буду робити
Хвостом буду поганять та на Гречку орать

Добрий Вечір!','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233890'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_233890','Ой Коляда Колядниця дайте Мачку до Кутиці','Ой Коляда Колядниця дайте Мачку до Кутиці
Як не дасте одкажіте моїх ніжок не знобіте
Я Дитинка Маленькая в мене ніжка босенькая
Вечір Добрий дайте Пиріг Довгий!
