INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2340859','Гопак','Музика: Олександр Злотник Слова: Леонід Ямковий','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує ансамбль "Цьомочки", художній керівник - Галина Равлінко.','Щоб зробить таке веселе,
Щоб в усіх-усіх оселях
Діти радісні були?
Нумо, разом почали!

Приспів:
Гей, гоп, гопака,     |
Ось тобі моя рука.    |
Узялися всі за руки,  |
Вище, вище закаблуки! | (2)

Щоб зробить таке хороше,
Щоб розвіялась пороша,
І на вулиці моїй
Заспівали солов''ї?

Приспів.

Щоб зробить таке важливе,
Щоб усі були щасливі?
Ти і я, вони і ми,
Ну, подумайте самі.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2340859'), datetime('now')),datetime('now'));
