INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2342522','З днем народження, бабуся!','Музика: Жанна Колмагорова Слова: Жанна Колмагорова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У мій день народження
Ти стала бабусею,
Ти про мене дуже довго мріяла,
Довго чекала і ходила колами,
Ти про мене щогодини говорила...
Перед тобою вдячна внучка,
В руках у мене не блокнот і не ручка,
Прямо зі сцени тебе вітаю:
Дуже люблю, бути коханою бажаю!

Приспів:
З днем народження, бабуся!
Цю пісню я тобі дарую!
З днем народження, бабуся!
Як же сильно я тебе люблю!
Ти ж знаєш, бабуся,
Для мене ти - самий вірний друг,
Не зможу я, бабуся,
Без тепла твоїх ніжних рук!

Перші літери, перші склади,
Ось ми з тобою на шкільному порозі,
Перший учитель і ти зі мною поруч,
Поруч зі мною і серцем, і поглядом.
Перед тобою вдячна внучка,
В руках у мене не блокнот і не ручка,
Прямо зі сцени тебе вітаю:
Дуже люблю, бути коханою бажаю!

Приспів.

З днем народження, бабуся!','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2342522'), datetime('now')),datetime('now'));
