INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2341920','Вірю','Музика: В''ячеслав Рибіков Слова: В''ячеслав Рибіков. Виконує: В''ячеслав Рибіков, Брія Блессінг','uk','ukraine_1991',NULL,NULL,'https://www.youtube.com/watch?v=t-jX7M19CB0&list=RDMMt-jX7M19CB0','Патріотичні пісні, Пісні АТО.','Відчуваєш чи ні, як горить земля?
Під ногами твоїми лежить зброя,
Ти не можеш повірить, що бачиш Ти
Твоє серце палає у вогні...

Приспів:
Вірю я, весна прийде
Разом скажем: "Ні війні!"
Нам поможе Бог встати -
Будемо завжди вільні!

Я Бажаю, щоб мир прийшов в серця!
Кожна людина мріє жити, де весна!
І нехай ми відчуваємо, як сонце гріє,
Це є те, про що кожен мріє!

Приспів. (2)','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2341920'), datetime('now')),datetime('now'));
