INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234216','На Щастя на Здоров''я на Новий Рік','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пасла Маланка Два Качура Роди Боже Жито й Пшеницю. Символіка Щедрого Вечера і Василя. Щедрий Вечер, 13-14 січня, зачинається властиво під Новий Рік (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Стежки до інших листків про Українські традиції.','Відміна 1:

На Щастя на Здоров''я на Новий Рік
Аби вам си родило
Краще як торік
Жито-Пшениця
Всяка Пашниця
Колопні по стелю
Сорочка по землю
А Лен по коліна
Аби вас хрещених
Голова не боліла
Будьте здорові
З Новим Роком! З Василем!

Відміна 2:

На Щастя на Здоров''я на Новий Рік !
Роди Боже лучче чим торік
Жито-Пшеницю Всяку Паляницю
Картоплю як довбня Коноплі під стелю
Льон по коліна щоб у Вас ні спина ні голова не боліли
Здрастуйте з Новим Роком !

Відміна 3:

На Щастя на Здоров''я на Новий Рік !
Роди Боже Жито-Пшеницю і Всяку Пашницю
Із Снопика мірка а з Колоска жмінька !

Відміна 4:

На Щастя на Здоров''я на Новий Рік !
Роди Боже Жито-Пшеницю і Всяку Пашницю
Коноплі під стелю Льон по коліна
Щоб у Ваших хрещених голова не боліла
Будьте здорові з Святом та з Новим Роком !

Відміна 5:

На Щастя на Здоров''я на Новий Год !
Дай Боже Жито-Пшеницю
Всяку Паляницю і Дітей копицю
З Новим Роком Вас вітаєм
Щастя й Долі Вам бажаєм
Щоб у Вашому Селі було повно на Столі','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:shchedrivky'', ''Колядки'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_234216'), datetime('now')),datetime('now'));
